### 🎵 3. 更新 `flybird_game/script.js`

```javascript
// Get DOM elements
const canvas = document.getElementById('game-canvas');
const ctx = canvas.getContext('2d');
const startScreen = document.getElementById('start-screen');
const gameOverScreen = document.getElementById('game-over');
const startBtn = document.getElementById('start-btn');
const pauseBtn = document.getElementById('pause-btn');
const scoreEl = document.getElementById('score');
const historyEl = document.getElementById('history');
const finalScoreEl = document.getElementById('final-score');
const highScoreEl = document.getElementById('high-score');
const historyDisplay = document.getElementById('history-display');
const restartBtn = document.getElementById('restart-btn');
const soundToggle = document.getElementById('sound-toggle');

// Audio setup
const jumpSound = new Audio('https://freesound.org/data/previews/388/388275_5228863-lq.mp3');
const gameOverSound = new Audio('https://freesound.org/data/previews/152/152595_3176341-lq.mp3');
const bgMusic = new Audio('https://freesound.org/data/previews/242/242392_4504565-lq.mp3');
bgMusic.loop = true;

// Game variables
let gameRunning = false;
let gamePaused = false;
let score = 0;
let history = [];
let lastTime = 0;
let deltaTime = 0;
let highScore = 0;

// Bird properties
const bird = {
    x: 50,
    y: 300,
    width: 34,
    height: 24,
    velocity: 0,
    gravity: 0.5,
    jumpStrength: -8
};

// Pipes properties
let pipes = [];
const pipeGap = 150;
const pipeDistance = 200;
const pipeWidth = 60;
let pipeDistanceCounter = 0;

// Background color
const skyColor = '#7fb3d5';

// Toggle sound
function toggleSound() {
    const isMuted = !soundToggle.checked;
    if (isMuted) {
        jumpSound.pause();
        gameOverSound.pause();
        bgMusic.pause();
    } else {
        if (!bgMusic.paused) bgMusic.play();
    }
}

// Play sound
function playSound(sound, volume = 0.5) {
    if (soundToggle.checked) {
        sound.currentTime = 0;
        sound.volume = volume;
        sound.play().catch(e => console.log("Audio play error:", e));
    }
}

// Draw bird
function drawBird() {
    ctx.fillStyle = 'yellow';
    ctx.fillRect(bird.x, bird.y, bird.width, bird.height);

    // Draw eye
    ctx.fillStyle = 'black';
    ctx.beginPath();
    ctx.arc(bird.x + 28, bird.y + 12, 4, 0, Math.PI * 2);
    ctx.fill();

    // Add wing flap effect
    ctx.fillStyle = 'rgba(255, 200, 0, 0.3)';
    ctx.beginPath();
    ctx.moveTo(bird.x + 10, bird.y + 10);
    ctx.lineTo(bird.x + 20, bird.y + 5);
    ctx.lineTo(bird.x + 20, bird.y + 15);
    ctx.closePath();
    ctx.fill();
}

// Draw pipes
function drawPipes() {
    ctx.fillStyle = 'green';
    pipes.forEach(pipe => {
        // Top pipe
        ctx.fillRect(pipe.x, 0, pipeWidth, pipe.height);

        // Bottom pipe
        ctx.fillRect(pipe.x, pipe.height + pipeGap, pipeWidth, canvas.height - (pipe.height + pipeGap));
    });
}

// Update bird position
function updateBird() {
    if (!gameRunning || gamePaused) return;

    bird.velocity += bird.gravity;
    bird.y += bird.velocity;

    // Ground collision
    if (bird.y + bird.height > canvas.height) {
        gameOver();
    }

    // Ceiling collision
    if (bird.y < 0) {
        gameOver();
    }
}

// Create new pipe
function createPipe() {
    const minHeight = 50;
    const maxHeight = canvas.height - pipeGap - minHeight;
    const height = Math.floor(Math.random() * (maxHeight - minHeight + 1)) + minHeight;

    pipes.push({
        x: canvas.width,
        y: 0,
        height: height,
        passed: false
    });
}

// Update pipes
function updatePipes() {
    if (!gameRunning || gamePaused) return;

    pipes.forEach(pipe => {
        pipe.x -= 2;

        if (!pipe.passed && pipe.x + pipeWidth < bird.x) {
            pipe.passed = true;
            score += 1;
            scoreEl.textContent = `得分: ${score}`;
            playSound(jumpSound, 0.3);
        }

        if (
            bird.x + bird.width > pipe.x &&
            bird.x < pipe.x + pipeWidth &&
            (bird.y < pipe.height || bird.y + bird.height > pipe.height + pipeGap)
        ) {
            gameOver();
        }
    });

    pipeDistanceCounter += 2;

    if (pipeDistanceCounter >= pipeDistance) {
        createPipe();
        pipeDistanceCounter = 0;
    }

    pipes = pipes.filter(pipe => pipe.x + pipeWidth > 0);
}

// Game over function
function gameOver() {
    gameRunning = false;
    history.push(score);
    if (score > highScore) {
        highScore = score;
        highScoreEl.innerHTML = `<span style="color:#00ff9d;">✨ 新纪录！${highScore}</span>`;
    } else {
        highScoreEl.textContent = `当前最高分: ${highScore}`;
    }

    finalScoreEl.textContent = `你的得分: ${score}`;
    historyDisplay.textContent = history.join(', ');

    // Show game over screen
    gameOverScreen.classList.add('active');
    playSound(gameOverSound);
    bgMusic.pause();
}

// Start game
function startGame() {
    if (gameRunning) return;

    gameRunning = true;
    gamePaused = false;
    score = 0;
    scoreEl.textContent = `得分: ${score}`;
    pipes = [];
    bird.y = 300;
    bird.velocity = 0;

    // Reset screens
    startScreen.classList.remove('active');
    gameOverScreen.classList.remove('active');

    // Initialize
    pipeDistanceCounter = 0;
    createPipe();

    // Resume music
    if (soundToggle.checked) {
        bgMusic.play().catch(e => console.log("Background music error:", e));
    }

    // Start animation loop
    lastTime = performance.now();
    animate();
}

// Pause game
function pauseGame() {
    if (!gameRunning) return;

    gamePaused = !gamePaused;
    pauseBtn.textContent = gamePaused ? '继续' : '暂停';

    if (!gamePaused) {
        requestAnimationFrame(animate);
    }
